        sepia_color = mix(vec3(0.9, 0.1, 0.05), vec3(1.0, 1.0, 0.2), (luminance - 0.7) / 0.3);

    gl_FragColor = vec4(clamp(sepia_color, 0.0, 1.0), 1.0);
}

